import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'gov-n8n-project',
  apiKey: process.env.VEX_API_KEY,
});

export async function validateAgentOutput($input) {
  const agentOutput = $input.all()[0].json;

  const result = await vex.evaluate({
    inputs: {
      prompt: agentOutput.prompt,
      response: agentOutput.response,
      toolsCalled: agentOutput.tools || [],
      workflowId: $workflow.id
    },
    rules: [
      'NO_RECURSION',
      'NO_CLASSIFIED_DATA',
      'EXPLAINABLE_OUTPUT',
      'NO_CREDENTIALS'
    ],
    sensitivity: 'critical'
  });

  if (!result.pass) {
    throw new Error(`Vex blocked: ${result.violations.join(', ')}`);
  }

  return [{ json: agentOutput }];
}

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'gov-n8n-project' });

export async function scanToolParams($input) {
  const toolCall = $input.all()[0].json;

  const check = await vex.evaluate({
    inputs: {
      toolName: toolCall.name,
      parameters: toolCall.parameters,
      userIntent: $json.userQuery
    },
    rules: ['NO_CLASSIFIED_MARKERS'],
    context: {
      classification: 'SECRET//NOFORN',
      fedramp: true
    }
  });

  if (check.violations.includes('CLASSIFIED_DATA_DETECTED')) {
    return [{ json: { blocked: true, reason: 'Classified data prohibited' } }];
  }

  return [{ json: toolCall }];
}

import { Vex } from '@vex_dev/sdk';

export async function ensureExplainability($input) {
  const decision = $input.all()[0].json;

  if (decision.affectsCitizens) {
    const audit = await vex.audit({
      decision: decision.output,
      reasoning: decision.thoughtProcess || '',
      impactLevel: 'high',
      rules: ['EXPLAINABLE', 'APPEALABLE'],
      metadata: {
        agency: 'HHS',
        program: 'Medicaid_Eligibility',
        timestamp: new Date().toISOString()
      }
    });

    if (!audit.compliant) {
      return [{ json: { requiresReview: true, auditId: audit.id } }];
    }
  }

  return [{ json: { approved: true } }];
}
